static int counter = 0, node = 0;

    static int kthLargest(Node root, int k) {
        counter = k;
        inOrder(root);
        return node;
    }

    static void inOrder(Node root) {
        if (root.right != null) {
            inOrder(root.right);
        }

        counter--;
        if (counter == 0) {
            node = root.val;
            return;
        }

        if (root.left != null) {
            inOrder(root.left);
        }
